function getHeaders(csvText) {
  if (!csvText) return [];
  const firstLine = csvText.trim().split('
')[0];
  const headers = [];
  let inQuote = false, current = '';
  for (const char of firstLine) {
    if (char === '"') { inQuote = !inQuote; }
    else if (char === ',' && !inQuote) { headers.push(current.trim().replace(/^"|"$/g,'')); current = ''; }
    else { current += char; }
  }
  headers.push(current.trim().replace(/^"|"$/g,''));
  return headers;
}
function getSampleRows(csvText, n) {
  if (!csvText) return [];
  return csvText.trim().split('
').slice(1, n+1);
}

const body            = $input.first().json.body;
const staffingHeaders = getHeaders(body.staffing_csv);
const rateHeaders     = getHeaders(body.rate_card_csv);
const vacationHeaders = getHeaders(body.vacation_csv);
const bandHeaders     = getHeaders(body.band_cost_csv);
const staffingSample  = getSampleRows(body.staffing_csv, 2);
const rateSample      = getSampleRows(body.rate_card_csv, 2);
const vacationSample  = getSampleRows(body.vacation_csv, 2);
const bandSample      = getSampleRows(body.band_cost_csv, 2);

const mappingPrompt = `You are a data analyst. Map column headers from uploaded files to standard field names.

--- STAFFING FILE ---
Headers: ${JSON.stringify(staffingHeaders)}
Sample rows:
${staffingSample.join('
')}

--- ROLE RATE CARD FILE (Client Revenue rates) ---
Headers: ${JSON.stringify(rateHeaders)}
Sample rows:
${rateSample.join('
')}

--- VACATION FILE ---
Headers: ${JSON.stringify(vacationHeaders)}
Sample rows:
${vacationSample.join('
')}

--- BAND COST CARD FILE (Internal cost rates by band) ---
Headers: ${JSON.stringify(bandHeaders)}
Sample rows:
${bandSample.join('
')}

Map to these required standard fields:

STAFFING FILE needs:
- resource_name: the person full name
- client_bill_role: the role used to bill the client (links to Rate Card for REVENUE)
- consulting_band_role: the internal consulting band (e.g. Band 6, Band 7) used for COST lookup
- start_date: project start date YYYY-MM-DD
- end_date: project end date YYYY-MM-DD
- work_numbers: WBS or charge codes with optional % allocation
- weekly_hours: contracted hours per week (default 40 if not found)

ROLE RATE CARD FILE needs:
- client_bill_role: the role name that matches the staffing client_bill_role
- hourly_revenue_rate: the column containing the monetary rate per hour OR per day (pick whichever exists). Return ONLY the exact column header string as it appears in the file. Do NOT compute or divide anything.

VACATION FILE needs:
- resource_name: person full name
- vacation_start: leave start date
- vacation_end: leave end date

BAND COST CARD FILE needs:
- consulting_band_role: the band label that matches staffing consulting_band_role (e.g. Band 6, Band 7)
- hourly_cost_rate: the column containing the monetary cost rate per hour OR per day (pick whichever exists). Return ONLY the exact column header string as it appears in the file. Do NOT compute or divide anything.

CRITICAL RULES:
1. Values must be EXACT column header strings copied verbatim from the Headers lists above.
2. Do NOT write expressions, formulas, or calculations (e.g. never write "Column / 8").
3. If a column is a day rate (e.g. "Standard Day Rate"), return that exact name — the code will handle dividing by 8.
4. Return ONLY valid JSON, no markdown, no explanation.

Return exactly this structure:
{
  "staffing": {
    "resource_name": "exact col name or null",
    "client_bill_role": "exact col name or null",
    "consulting_band_role": "exact col name or null",
    "start_date": "exact col name or null",
    "end_date": "exact col name or null",
    "work_numbers": "exact col name or null",
    "weekly_hours": "exact col name or 40"
  },
  "rate_card": {
    "client_bill_role": "exact col name or null",
    "hourly_revenue_rate": "exact col name or null"
  },
  "vacation": {
    "resource_name": "exact col name or null",
    "vacation_start": "exact col name or null",
    "vacation_end": "exact col name or null"
  },
  "band_cost": {
    "consulting_band_role": "exact col name or null",
    "hourly_cost_rate": "exact col name or null"
  },
  "confidence": "high",
  "warnings": []
}`;

const ollamaPayload = {
  model: "llama3.1:8b",
  prompt: mappingPrompt,
  stream: false,
  format: "json",
  options: { temperature: 0.0, num_predict: 512 }
};

return [{ json: { ollamaPayload, originalData: body } }];

const input        = $input.first().json;
const originalData = $node["Extract Headers"].json.originalData;
if (input.error) return [{ json: { error: input.error } }];
const ollamaRaw = input.response || '';
let rawMapping;
try {
  rawMapping = JSON.parse(ollamaRaw.replace(/```json/gi,'').replace(/```/g,'').trim());
} catch(e) {
  return [{ json: { error: 'Column mapping failed. Raw: ' + ollamaRaw.substring(0,200) } }];
}
const mapping = {
  staffing:  rawMapping.staffing  || {},
  rate_card: rawMapping.rate_card || {},
  vacation:  rawMapping.vacation  || {},
  band_cost: rawMapping.band_cost || {}
};
// Validate critical staffing fields
const critical = ['resource_name','client_bill_role','consulting_band_role','start_date','end_date','work_numbers'];
const missing  = critical.filter(f => !mapping.staffing[f]);
if (missing.length > 0) {
  return [{ json: { error: `Could not map staffing columns: ${missing.join(', ')}`, mapping } }];
}
if (!mapping.rate_card.client_bill_role || !mapping.rate_card.hourly_revenue_rate) {
  return [{ json: { error: 'Could not find client bill role and revenue rate in Rate Card file.', mapping } }];
}
if (!mapping.band_cost.consulting_band_role || !mapping.band_cost.hourly_cost_rate) {
  return [{ json: { error: 'Could not find consulting band role and cost rate in Band Cost Card file.', mapping } }];
}
// Detect day rate columns so Parse & Calculate can divide by 8
const revColName = String(mapping.rate_card.hourly_revenue_rate||'').toLowerCase();
const costColName = String(mapping.band_cost.hourly_cost_rate||'').toLowerCase();
mapping.rate_card._revenue_is_day_rate = revColName.includes('day') || revColName.includes('daily');
mapping.band_cost._cost_is_day_rate = costColName.includes('day') || costColName.includes('daily');

return [{ json: { mapping, confidence: rawMapping.confidence||'unknown', warnings: rawMapping.warnings||[], originalData } }];

const mapping      = $node["Validate Mapping"].json.mapping || {};
const warnings     = $node["Validate Mapping"].json.warnings || [];
const originalData = $node["Extract Headers"].json.originalData;
const safeMapping  = {
  staffing:  mapping.staffing  || {},
  rate_card: mapping.rate_card || {},
  vacation:  mapping.vacation  || {},
  band_cost: mapping.band_cost || {}
};

function parseCSV(csvText, colMap) {
  if (!csvText || !colMap || !Object.keys(colMap).length) return [];
  const lines = csvText.trim().split('\n');
  const rawH  = lines[0].split(',').map(h => h.trim().replace(/^"|"$/g,''));
  const idx   = {};
  for (const [std, real] of Object.entries(colMap)) {
    if (!real) continue;
    const ci = rawH.findIndex(h => h.toLowerCase().trim() === String(real).toLowerCase().trim());
    idx[std] = ci !== -1 ? { ci } : { dv: String(real) };
  }
  return lines.slice(1).filter(l => l.trim()).map(line => {
    const vals = []; let q = false, cur = '';
    for (const c of line) {
      if (c==='"'){q=!q;}
      else if(c===','&&!q){vals.push(cur.trim().replace(/^"|"$/g,''));cur='';}
      else{cur+=c;}
    }
    vals.push(cur.trim().replace(/^"|"$/g,''));
    const o = {};
    for (const [std,src] of Object.entries(idx)) {
      o[std] = 'dv' in src ? src.dv : (vals[src.ci]||'');
    }
    return o;
  });
}

function workDays(s,e,vSet) {
  const start=new Date(s),end=new Date(e);
  if(isNaN(start)||isNaN(end)) return 0;
  let d=0; const cur=new Date(start);
  while(cur<=end){
    if(cur.getDay()!==0&&cur.getDay()!==6&&!vSet.has(cur.toISOString().split('T')[0]))d++;
    cur.setDate(cur.getDate()+1);
  }
  return d;
}
function expandVac(rows) {
  const m={};
  for(const r of rows){
    const n=(r.resource_name||'').trim(); if(!n) continue;
    if(!m[n]) m[n]=new Set();
    const s=new Date(r.vacation_start),e=new Date(r.vacation_end);
    if(isNaN(s)||isNaN(e)) continue;
    const c=new Date(s);
    while(c<=e){m[n].add(c.toISOString().split('T')[0]);c.setDate(c.getDate()+1);}
  }
  return m;
}
function months(s,e){
  const ms=[],end=new Date(e);
  const c=new Date(new Date(s).getFullYear(),new Date(s).getMonth(),1);
  if(isNaN(c)||isNaN(end)) return ms;
  while(c<=end){ms.push(`${c.getFullYear()}-${String(c.getMonth()+1).padStart(2,'0')}`);c.setMonth(c.getMonth()+1);}
  return ms;
}
function mDays(mo,ps,pe,vSet){
  const [y,m]=mo.split('-').map(Number);
  const s=new Date(y,m-1,1),e=new Date(y,m,0);
  const es=new Date(Math.max(new Date(ps),s)),ee=new Date(Math.min(new Date(pe),e));
  if(es>ee) return 0;
  return workDays(es.toISOString().split('T')[0],ee.toISOString().split('T')[0],vSet);
}
function parseWBS(s){
  if(!s) return [];
  return s.split(',').map(p=>{
    p=p.trim(); const i=p.indexOf(':');
    if(i===-1) return {wbs:p,pct:1};
    return {wbs:p.substring(0,i).trim(),pct:parseFloat(p.substring(i+1).replace('%','').trim())/100};
  }).filter(a=>a.wbs);
}
const r2=n=>Math.round(n*100)/100;

// Parse all 4 files
const staffing = parseCSV(originalData.staffing_csv,  safeMapping.staffing);
const rateRows = parseCSV(originalData.rate_card_csv, safeMapping.rate_card);
const vacRows  = parseCSV(originalData.vacation_csv,  safeMapping.vacation);
const bandRows = parseCSV(originalData.band_cost_csv, safeMapping.band_cost);

// Revenue lookup: client_bill_role -> hourly revenue rate
// LLM sometimes maps to "Standard Day Rate / 8" — handle both day and hourly
const _revColMapped = String(safeMapping.rate_card.hourly_revenue_rate||'').toLowerCase();
const _revIsDay = _revColMapped.includes('day') || _revColMapped.includes('/8') || _revColMapped.includes('/ 8');
const revenueMap = {};
for(const row of rateRows){
  const role=(row.client_bill_role||'').trim();
  if(!role) continue;
  let rate = parseFloat(row.hourly_revenue_rate);
  if(isNaN(rate)) {
    // Fallback: scan all numeric columns
    for(const [k,v] of Object.entries(row)) {
      const n = parseFloat(v);
      if(!isNaN(n) && n > 10 && n < 10000 && k !== 'client_bill_role') { rate = n; break; }
    }
  }
  if(_revIsDay && !isNaN(rate)) rate = Math.round(rate/8*100)/100;
  if(role && !isNaN(rate) && rate > 0) revenueMap[role] = rate;
}

// Cost lookup: consulting_band_role -> hourly cost rate
// LLM sometimes maps to "Daily Cost Rate / 8" — handle both day and hourly
const _costColMapped = String(safeMapping.band_cost.hourly_cost_rate||'').toLowerCase();
const _costIsDay = _costColMapped.includes('day') || _costColMapped.includes('/8') || _costColMapped.includes('/ 8');
const costMap = {};
for(const row of bandRows){
  const band=(row.consulting_band_role||'').trim();
  if(!band) continue;
  let cost = parseFloat(row.hourly_cost_rate);
  if(isNaN(cost)) {
    for(const [k,v] of Object.entries(row)) {
      const n = parseFloat(v);
      if(!isNaN(n) && n > 5 && n < 10000 && k !== 'consulting_band_role') { cost = n; break; }
    }
  }
  if(_costIsDay && !isNaN(cost)) cost = Math.round(cost/8*100)/100;
  if(band && !isNaN(cost) && cost > 0) costMap[band] = cost;
}
const vacMap={}, unmappedRoles=new Set(), unmappedBands=new Set();
for(const [n,s] of Object.entries(expandVac(vacRows))) vacMap[n]=s;

const wbsData={};

for(const row of staffing){
  const name         = (row.resource_name||'').trim();
  const billRole     = (row.client_bill_role||'').trim();
  const bandRole     = (row.consulting_band_role||'').trim();
  // Case-insensitive lookup with whitespace normalisation
  const billRoleKey  = billRole.toLowerCase().replace(/\s+/g,' ');
  const bandRoleKey  = bandRole.toLowerCase().replace(/\s+/g,' ');
  const revenueRate  = revenueMap[billRole]
    ?? Object.entries(revenueMap).find(([k])=>k.toLowerCase().replace(/\s+/g,' ')===billRoleKey)?.[1];
  const costRate     = costMap[bandRole]
    ?? Object.entries(costMap).find(([k])=>k.toLowerCase().replace(/\s+/g,' ')===bandRoleKey)?.[1];
  const dailyHrs     = (parseFloat(row.weekly_hours)||40)/5;
  const allocs       = parseWBS(row.work_numbers);
  const myVac        = vacMap[name]||new Set();
  const ms           = months(row.start_date, row.end_date);

  if(!name||!row.start_date||!row.end_date) continue;
  if(revenueRate===undefined) unmappedRoles.add(billRole);
  if(costRate===undefined)    unmappedBands.add(bandRole);

  for(const a of allocs){
    if(!a.wbs) continue;
    if(!wbsData[a.wbs]) wbsData[a.wbs]={work_number:a.wbs,resources:[],monthly_summary:{}};

    const res={
      name, client_bill_role:billRole, consulting_band_role:bandRole,
      allocation_pct: Math.round(a.pct*100),
      revenue_rate:   revenueRate||0,
      cost_rate:      costRate||0,
      start_date:     row.start_date,
      end_date:       row.end_date,
      vacation_days:  [...myVac].filter(d=>d>=row.start_date&&d<=row.end_date).length,
      monthly_hours:{}, monthly_revenue:{}, monthly_cost:{}, monthly_margin:{}
    };

    let totHrs=0,totRev=0,totCost=0;
    for(const mo of ms){
      const d   = mDays(mo,row.start_date,row.end_date,myVac);
      const hrs = Math.round(d*dailyHrs*a.pct*10)/10;
      const rev = r2(hrs*(revenueRate||0));
      const cst = r2(hrs*(costRate||0));
      const mgn = r2(rev-cst);
      res.monthly_hours[mo]=hrs;
      res.monthly_revenue[mo]=rev;
      res.monthly_cost[mo]=cst;
      res.monthly_margin[mo]=mgn;
      totHrs+=hrs; totRev+=rev; totCost+=cst;
      if(!wbsData[a.wbs].monthly_summary[mo])
        wbsData[a.wbs].monthly_summary[mo]={total_hours:0,total_revenue:0,total_cost:0,total_margin:0};
      wbsData[a.wbs].monthly_summary[mo].total_hours   +=hrs;
      wbsData[a.wbs].monthly_summary[mo].total_revenue +=rev;
      wbsData[a.wbs].monthly_summary[mo].total_cost    +=cst;
      wbsData[a.wbs].monthly_summary[mo].total_margin  +=r2(rev-cst);
    }
    res.total_hours   = Math.round(totHrs*10)/10;
    res.total_revenue = r2(totRev);
    res.total_cost    = r2(totCost);
    res.total_margin  = r2(totRev-totCost);
    res.margin_pct    = totRev>0 ? Math.round((totRev-totCost)/totRev*1000)/10 : 0;
    wbsData[a.wbs].resources.push(res);
  }
}

for(const k of Object.keys(wbsData)){
  const w=wbsData[k];
  w.grand_total_hours   = Math.round(w.resources.reduce((s,r)=>s+r.total_hours,  0)*10)/10;
  w.grand_total_revenue = r2(w.resources.reduce((s,r)=>s+r.total_revenue,0));
  w.grand_total_cost    = r2(w.resources.reduce((s,r)=>s+r.total_cost,   0));
  w.grand_total_margin  = r2(w.grand_total_revenue-w.grand_total_cost);
  w.grand_margin_pct    = w.grand_total_revenue>0
    ? Math.round((w.grand_total_margin/w.grand_total_revenue)*1000)/10 : 0;
  for(const mo of Object.keys(w.monthly_summary)){
    const ms=w.monthly_summary[mo];
    ms.total_hours   = Math.round(ms.total_hours*10)/10;
    ms.total_revenue = r2(ms.total_revenue);
    ms.total_cost    = r2(ms.total_cost);
    ms.total_margin  = r2(ms.total_margin);
    ms.margin_pct    = ms.total_revenue>0
      ? Math.round((ms.total_margin/ms.total_revenue)*1000)/10 : 0;
  }
}

const allWarnings=[
  ...(warnings||[]),
  ...[...unmappedRoles].map(r=>`No revenue rate for Client Bill Role: "${r}"`),
  ...[...unmappedBands].map(b=>`No cost rate for Consulting Band Role: "${b}"`)
];

return [{json:{wbsData, mapping:safeMapping, allWarnings}}];

const {wbsData, mapping, allWarnings} = $input.first().json;
const today = new Date().toISOString().split('T')[0];
const r2 = n => Math.round(n*100)/100;

const workNumbers = Object.values(wbsData).map(wbs => {
  const monthlySummary = {};
  for(const [mo,d] of Object.entries(wbs.monthly_summary)){
    monthlySummary[mo]={
      hours:       d.total_hours,
      revenue_usd: d.total_revenue,
      cost_usd:    d.total_cost,
      margin_usd:  d.total_margin,
      margin_pct:  d.margin_pct
    };
  }
  return {
    work_number:         wbs.work_number,
    grand_total_hours:   wbs.grand_total_hours,
    grand_total_revenue: wbs.grand_total_revenue,
    grand_total_cost:    wbs.grand_total_cost,
    grand_total_margin:  wbs.grand_total_margin,
    grand_margin_pct:    wbs.grand_margin_pct,
    resource_count:      wbs.resources.length,
    monthly_summary:     monthlySummary,
    resources: wbs.resources.map(res=>({
      name:                 res.name,
      client_bill_role:     res.client_bill_role,
      consulting_band_role: res.consulting_band_role,
      allocation_pct:       res.allocation_pct,
      revenue_rate:         res.revenue_rate,
      cost_rate:            res.cost_rate,
      total_hours:          res.total_hours,
      total_revenue:        res.total_revenue,
      total_cost:           res.total_cost,
      total_margin:         res.total_margin,
      margin_pct:           res.margin_pct,
      vacation_days:        res.vacation_days,
      start_date:           res.start_date,
      end_date:             res.end_date
    }))
  };
});

const report = {
  report_date:         today,
  grand_total_hours:   Math.round(workNumbers.reduce((s,w)=>s+w.grand_total_hours,  0)*10)/10,
  grand_total_revenue: r2(workNumbers.reduce((s,w)=>s+w.grand_total_revenue,0)),
  grand_total_cost:    r2(workNumbers.reduce((s,w)=>s+w.grand_total_cost,   0)),
  grand_total_margin:  r2(workNumbers.reduce((s,w)=>s+w.grand_total_margin, 0)),
  data_warnings:       allWarnings||[],
  work_numbers:        workNumbers
};
report.grand_margin_pct = report.grand_total_revenue>0
  ? Math.round((report.grand_total_margin/report.grand_total_revenue)*1000)/10 : 0;

return [{ json: { report, mapping } }];
